// ============================================================
// Confronto de totais e titulo a titulo
// Criterio: total do extrato bancario = total baixado no ERP
// Tolerancia: diferenca < R$ 0,01
// ============================================================

const CONTA = process.env.BANCO_CONTA || '0000-0';
const TOLERANCIA = 0.01;

const bancoRaw  = $('Banco - Extrato D-1').all();
const erpRaw    = $('ERP - Pagos D-1').all();
const dataAlvo  = $('Parametros de Execucao').first().json.dataAlvo;
const tsInicio  = $('Parametros de Execucao').first().json.tsInicio;

// Normaliza lista do banco (aceita array direto ou wrapper { data: [...] })
let bancoList = [];
for (const item of bancoRaw) {
  const raw = item.json;
  const lancamentos = raw.data ?? raw.lancamentos ?? (Array.isArray(raw) ? raw : [raw]);
  for (const l of lancamentos) {
    if (!l || !l.numero_documento) continue;
    bancoList.push({
      numero_documento: String(l.numero_documento).trim(),
      valor:            parseFloat(l.valor ?? 0),
      tipo:             l.tipo ?? 'DEBITO',
      descricao:        l.descricao ?? '',
      beneficiario:     l.beneficiario ?? '',
      data_pagamento:   l.data_pagamento ?? l.data_lancamento ?? dataAlvo,
      saldo_apos:       parseFloat(l.saldo_apos ?? 0)
    });
  }
}

const erpList = erpRaw.map(item => ({
  numero_documento: String(item.json.numero_documento ?? '').trim(),
  valor:            parseFloat(item.json.valor ?? 0),
  data_baixa:       item.json.data_baixa ?? dataAlvo,
  data_vencimento:  item.json.data_vencimento ?? '',
  historico:        item.json.historico ?? '',
  fornecedor:       item.json.fornecedor ?? '',
  status:           item.json.status ?? '',
  saldo_apos:       parseFloat(item.json.saldo_apos ?? 0)
}));

// --- 1. Valida totais ---
const valorBanco = bancoList.reduce((s, i) => s + i.valor, 0);
const valorERP   = erpList.reduce((s, i) => s + i.valor, 0);
const diferenca  = parseFloat((valorBanco - valorERP).toFixed(2));
const balanceado = Math.abs(diferenca) < TOLERANCIA;

// --- 2. Confronto titulo a titulo ---
const ok                = [];
const divergentes       = [];
const naoEncontradosERP = []; // no banco mas nao no ERP
const naoEncontradosBan = []; // no ERP mas nao no banco

const erpMap = {};
for (const e of erpList) erpMap[e.numero_documento] = e;

for (const bItem of bancoList) {
  const eItem = erpMap[bItem.numero_documento];
  if (!eItem) {
    naoEncontradosERP.push({
      numero_documento: bItem.numero_documento,
      valor_banco:      bItem.valor,
      valor_erp:        null,
      diferenca:        null,
      beneficiario:     bItem.beneficiario,
      data_pgto:        bItem.data_pagamento,
      status_conciliacao: 'NAO ENCONTRADO NO ERP'
    });
    continue;
  }
  const valorOk = Math.abs(bItem.valor - eItem.valor) < TOLERANCIA;
  const row = {
    numero_documento: bItem.numero_documento,
    valor_banco:      bItem.valor,
    valor_erp:        eItem.valor,
    diferenca:        parseFloat((bItem.valor - eItem.valor).toFixed(2)),
    beneficiario:     bItem.beneficiario || eItem.fornecedor,
    data_pgto:        bItem.data_pagamento,
    status_conciliacao: valorOk ? 'OK' : 'DIVERGENTE'
  };
  if (valorOk) ok.push(row); else divergentes.push(row);
}

for (const eItem of erpList) {
  if (!bancoList.find(i => i.numero_documento === eItem.numero_documento)) {
    naoEncontradosBan.push({
      numero_documento: eItem.numero_documento,
      valor_banco:      null,
      valor_erp:        eItem.valor,
      diferenca:        null,
      beneficiario:     eItem.fornecedor,
      data_pgto:        eItem.data_baixa,
      status_conciliacao: 'NAO ENCONTRADO NO BANCO'
    });
  }
}

const resultado = {
  conta: CONTA,
  dataAlvo,
  tsInicio,
  tsFim: new Date().toISOString(),
  totais: {
    valorBanco: parseFloat(valorBanco.toFixed(2)),
    valorERP:   parseFloat(valorERP.toFixed(2)),
    diferenca,
    balanceado
  },
  contagens: {
    ok:                ok.length,
    divergentes:       divergentes.length,
    naoEncontradosERP: naoEncontradosERP.length,
    naoEncontradosBan: naoEncontradosBan.length,
    total:             ok.length + divergentes.length + naoEncontradosERP.length + naoEncontradosBan.length
  },
  ok,
  divergentes,
  naoEncontradosERP,
  naoEncontradosBan
};

return [{ json: resultado }];

// ============================================================
// Geracao XLSX com 2 abas usando a lib 'xlsx'
//   Aba 1 - Divergencias (divergentes + nao encontrados)
//   Aba 2 - Confronto Completo (linha de totais + todos)
// ============================================================

const XLSX = require('xlsx');
const r = $input.first().json;

const linha = (row) => ({
  'No Documento':    row.numero_documento,
  'Valor Banco (R$)': row.valor_banco,
  'Valor ERP (R$)':   row.valor_erp,
  'Diferenca (R$)':   row.diferenca,
  'Status':           row.status_conciliacao,
  'Beneficiario':     row.beneficiario ?? '',
  'Data Pgto':        row.data_pgto ?? ''
});

const linhasDivergencias = [
  ...r.divergentes, ...r.naoEncontradosERP, ...r.naoEncontradosBan
].map(linha);

const todasLinhas = [
  ...r.ok, ...r.divergentes, ...r.naoEncontradosERP, ...r.naoEncontradosBan
].map(linha);

const totalRow = {
  'No Documento':     'TOTAL DO DIA',
  'Valor Banco (R$)': r.totais.valorBanco,
  'Valor ERP (R$)':   r.totais.valorERP,
  'Diferenca (R$)':   r.totais.diferenca,
  'Status':           r.totais.balanceado ? 'BALANCEADO' : 'NAO BATE',
  'Beneficiario':     '',
  'Data Pgto':        r.dataAlvo
};

const wb = XLSX.utils.book_new();

const wsDiv = XLSX.utils.json_to_sheet(
  linhasDivergencias.length ? linhasDivergencias
    : [{ 'Resultado': 'Sem divergencias nesta data', 'Data': r.dataAlvo }]
);
const wsComp = XLSX.utils.json_to_sheet([totalRow, {}, ...todasLinhas]);

XLSX.utils.book_append_sheet(wb, wsDiv,  'Divergencias');
XLSX.utils.book_append_sheet(wb, wsComp, 'Confronto Completo');

const buffer      = XLSX.write(wb, { type: 'buffer', bookType: 'xlsx' });
const nomeArquivo = `Conciliacao_Pagamentos_${r.dataAlvo}.xlsx`;

return [{
  json: { ...r, nomeArquivo },
  binary: {
    data: {
      data:     buffer.toString('base64'),
      mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      fileName: nomeArquivo
    }
  }
}];

const r = $('Confronto Totais + Titulos').first().json;
const arquivo = $('Gera Excel XLSX').first().json.nomeArquivo;

const temDiv = r.contagens.divergentes > 0 || r.contagens.naoEncontradosERP > 0 || r.contagens.naoEncontradosBan > 0;
const cor    = !r.totais.balanceado ? 'FF0000' : (temDiv ? 'FF8C00' : '00B050');
const titulo = !r.totais.balanceado
  ? `Conciliacao de Pagamentos - ${r.dataAlvo} - TOTAIS NAO BATEM`
  : (temDiv ? `Conciliacao de Pagamentos - ${r.dataAlvo} - ATENCAO: ha divergencias`
            : `Conciliacao de Pagamentos - ${r.dataAlvo} - Conciliado sem divergencias`);

const card = {
  '@type': 'MessageCard',
  '@context': 'http://schema.org/extensions',
  themeColor: cor,
  summary: `Conciliacao Pagamentos ${r.dataAlvo}`,
  sections: [{
    activityTitle: titulo,
    activitySubtitle: 'Resultado automatico - Contas a Pagar',
    facts: [
      { name: 'Total Banco:',      value: `R$ ${r.totais.valorBanco.toFixed(2)}` },
      { name: 'Total ERP:',        value: `R$ ${r.totais.valorERP.toFixed(2)}` },
      { name: 'Diferenca:',        value: `R$ ${r.totais.diferenca.toFixed(2)}` },
      { name: 'Titulos OK:',       value: String(r.contagens.ok) },
      { name: 'Divergentes:',      value: String(r.contagens.divergentes) },
      { name: 'Nao no ERP:',       value: String(r.contagens.naoEncontradosERP) },
      { name: 'Nao no Banco:',     value: String(r.contagens.naoEncontradosBan) },
      { name: 'Arquivo:',          value: arquivo }
    ]
  }]
};

return [{ json: { payload: JSON.stringify(card) } }];

